module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

parameter IDLE = 3'b000;
parameter SUB = 3'b001;
parameter ADD = 3'b010;
parameter SHIFT = 3'b011;
parameter FINALIZE = 3'b100;

reg [2:0] state, next_state;
reg [15:0] neg_divisor;
reg [31:0] sr;
reg [15:0] sub_result;
reg [16:0] carry;
reg [4:0] cnt;
reg start_cnt;
reg result_sign;
reg [15:0] dividend_abs;
reg [15:0] divisor_abs;
reg done;

always @(*) begin
    case (state)
        IDLE: begin
            if (opn_valid && !res_valid) begin
                next_state = SUB;
            end else begin
                next_state = IDLE;
            end
        end
        SUB: begin
            if (cnt[4]) begin
                next_state = FINALIZE;
            end else begin
                next_state = SHIFT;
            end
        end
        SHIFT: begin
            next_state = SUB;
        end
        FINALIZE: begin
            next_state = IDLE;
        end
        default: next_state = IDLE;
    endcase
end

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        state <= IDLE;
        done <= 0;
        neg_divisor <= 0;
        sr <= 0;
        sub_result <= 0;
        carry <= 0;
        cnt <= 0;
        start_cnt <= 0;
        result_sign <= 0;
        dividend_abs <= 0;
        divisor_abs <= 0;
        res_valid <= 0;
        result <= 0;
    end else begin
        state <= next_state;
        case (next_state)
            IDLE: begin
                if (opn_valid && !res_valid) begin
                    done <= 0;
                    if (divisor[15] && sign) begin
                        divisor_abs <= (~divisor) + 1;
                    end else begin
                        divisor_abs <= divisor;
                    end
                    if (dividend[15] && sign) begin
                        dividend_abs <= (~dividend) + 1;
                    end else begin
                        dividend_abs <= dividend;
                    end
                    result_sign <= (divisor[15] ^ dividend[15]) && sign;
                    sr <= {16'b0, dividend_abs};
                    neg_divisor <= (~divisor_abs) + 1;
                    cnt <= 1;
                    start_cnt <= 1;
                end
            end
            SUB: begin
                if (cnt[4]) begin
                    done <= 1;
                    start_cnt <= 0;
                end
                sub_result <= sr[31:16] + neg_divisor;
                carry <= sub_result[15] ? 17'b0 : 17'b1;
            end
            SHIFT: begin
                if (cnt[4]) begin
                    done <= 1;
                    start_cnt <= 0;
                end
                sr <= {carry[15:0], sr[15:0]};
                cnt <= cnt + 1;
            end
            FINALIZE: begin
                if (done) begin
                    result <= result_sign ? ~(sr[15:0] - 1) : sr[15:0];
                    res_valid <= 1;
                end
            end
        endcase
    end
end
endmodule
